const subReadme = `# sub

Package sub is a nested fixture package used to assert docsgen documents
subpackages, not just the module root.

## Reference

- API: <https://pkg.go.dev/example.com/sample/sub>
- Guide: [sub guide](https://example.com/sample/wiki/Sub)

<!-- Generated by cmd/docsgen (MC-11). Do not edit; run ` + "`make docs`" + `. -->
`

// copyFixture copies testdata/sample into a fresh temp dir so tests never
// write generated README.md files back into the repo's testdata tree.
func copyFixture(t *testing.T) string {
	t.Helper()

	dst := t.TempDir()
	src := filepath.Join("testdata", "sample")

	err := filepath.WalkDir(src, func(path string, d fs.DirEntry, err error) error {
		if err != nil {
			return err
		}

		rel, err := filepath.Rel(src, path)
		if err != nil {
			return err
		}
		target := filepath.Join(dst, rel)

		if d.IsDir() {
			return os.MkdirAll(target, 0o755)
		}

		data, err := os.ReadFile(path)
		if err != nil {
			return err
		}
		return os.WriteFile(target, data, 0o644)
	})
	require.NoError(t, err)

	return dst
}

func TestGenerate_RendersDocumentedPackages(t *testing.T) {
	root := copyFixture(t)

	err := Generate(root, Config{WikiBaseURL: "https://example.com/sample/wiki"})
	require.NoError(t, err)

	got, err := os.ReadFile(filepath.Join(root, "sub", "README.md"))
	require.NoError(t, err)
	assert.Equal(t, subReadme, string(got))
}

func TestGenerate_SkipsExcludedAndUndocumentedPackages(t *testing.T) {
	root := copyFixture(t)

	err := Generate(root, Config{WikiBaseURL: "https://example.com/sample/wiki"})
	require.NoError(t, err)

	skipped := []string{
		".", // module root: hand-authored README.md, never generated
		filepath.Join("cmd", "tool"),
		filepath.Join("internal", "helper"),
		filepath.Join("examples", "demo"),
		"nodoc",
		"empty",
	}
	for _, dir := range skipped {
		_, err := os.Stat(filepath.Join(root, dir, "README.md"))
		assert.Truef(t, os.IsNotExist(err), "expected no README.md under %s", dir)
	}
}

func TestGenerate_LogsDocumentedAndSkippedPackages(t *testing.T) {
	root := copyFixture(t)

	var lines []string
	err := Generate(root, Config{Logf: func(format string, args ...any) {
		lines = append(lines, fmt.Sprintf(format, args...))
	}})
	require.NoError(t, err)

	var wrote, skip int
	for _, l := range lines {
		switch {
		case strings.Contains(l, "docsgen: wrote"):
			wrote++
		case strings.Contains(l, "docsgen: skip"):
			skip++
		}
	}
	assert.Equal(t, 1, wrote) // sample/sub (module root is denylisted, never a wrote/skip line)
	assert.Equal(t, 2, skip)  // nodoc, empty
}

func TestGenerate_DefaultsWikiBaseFromModulePath(t *testing.T) {
	root := t.TempDir()
	require.NoError(t, os.WriteFile(filepath.Join(root, "go.mod"), []byte("module github.com/example/ghsample\n\ngo 1.26\n"), 0o644))
	require.NoError(t, os.MkdirAll(filepath.Join(root, "widget"), 0o755))
	require.NoError(t, os.WriteFile(filepath.Join(root, "widget", "widget.go"), []byte("// Package widget is a fixture for the default wiki base test.\npackage widget\n\n// Value is exported so widget has an exported identifier.\nconst Value = 1\n"), 0o644))

	require.NoError(t, Generate(root, Config{}))

	got, err := os.ReadFile(filepath.Join(root, "widget", "README.md"))
	require.NoError(t, err)
	assert.Contains(t, string(got), "https://github.com/example/ghsample/wiki/Widget")
}

func TestGenerate_OmitsGuideLineWhenWikiBaseEmpty(t *testing.T) {
	root := copyFixture(t) // example.com/sample: non-github.com, so defaultWikiBase("") stays ""

	require.NoError(t, Generate(root, Config{}))

	got, err := os.ReadFile(filepath.Join(root, "sub", "README.md"))
	require.NoError(t, err)
	content := string(got)

	assert.Contains(t, content, "- API: <https://pkg.go.dev/example.com/sample/sub>")
	assert.NotContains(t, content, "- Guide:")
	assert.NotContains(t, content, "/Sub)") // no malformed empty-base link
}

func TestGenerate_IsDeterministic(t *testing.T) {
	root := copyFixture(t)

	require.NoError(t, Generate(root, Config{WikiBaseURL: "https://example.com/sample/wiki"}))
	first, err := os.ReadFile(filepath.Join(root, "sub", "README.md"))
	require.NoError(t, err)

	require.NoError(t, Generate(root, Config{WikiBaseURL: "https://example.com/sample/wiki"}))
	second, err := os.ReadFile(filepath.Join(root, "sub", "README.md"))
	require.NoError(t, err)

	assert.Equal(t, first, second)
}

