func TestLoadPackageDoc_NoNonTestGoFiles(t *testing.T) {
	dir := t.TempDir()
	// Only a _test.go file present: it's excluded, leaving zero files and
	// thus zero distinct package names.
	require.NoError(t, os.WriteFile(filepath.Join(dir, "pkg_test.go"), []byte("package onlytest\n"), 0o644))

	pkg, ok, err := loadPackageDoc(dir, "example.com/onlytest")
	require.NoError(t, err)
	assert.False(t, ok)
	assert.Nil(t, pkg)
}

func TestDiscoverDirs_UnreadableSubdirError(t *testing.T) {
	if runtime.GOOS == "windows" {
		t.Skip("directory permission semantics differ on windows")
	}
	if os.Geteuid() == 0 {
		t.Skip("root ignores directory read permissions")
	}

	root := t.TempDir()
	require.NoError(t, os.WriteFile(filepath.Join(root, "go.mod"), []byte("module example.com/unreadable\n\ngo 1.26\n"), 0o644))
	blocked := filepath.Join(root, "blocked")
	require.NoError(t, os.MkdirAll(blocked, 0o755))
	require.NoError(t, os.Chmod(blocked, 0o000))
	t.Cleanup(func() { _ = os.Chmod(blocked, 0o755) })

	_, err := discoverDirs(root)
	assert.Error(t, err)

	err = Generate(root, Config{})
	assert.Error(t, err)
}
